let myChartInstance=null;let allocationChartInstance=null;let compareChartInstance=null;let benchmarkChartInstance=null;let benchmarkRange='month';let benchmarkLoaded=false;let taxLoaded=false;let bondsData=[];function onChartJsReady(fn){if(window.Chart){fn();return;}const script=document.querySelector('script[src*="chart.js"]');if(!script){setTimeout(()=>onChartJsReady(fn),100);return;}script.addEventListener('load',fn);}async function fetchActivePortfolio(){const response=await fetch('/api/portfolio');if(response.status===401){window.location.href='/';return;}const data=await response.json();const valEl=document.getElementById('total-portfolio-value');if(valEl)valEl.innerText=data.total_value.toLocaleString('ru-RU',{minimumFractionDigits:2});bondsData=data.bonds ||[];renderAllocationChart();}let allocationChartExpanded=false;function renderAllocationChart(){const canvas=document.getElementById('allocationChart');const emptyEl=document.getElementById('allocationEmpty');if(!canvas)return;if(!bondsData.length){if(emptyEl)emptyEl.style.display='block';if(allocationChartInstance){allocationChartInstance.destroy();allocationChartInstance=null;}return;}if(emptyEl)emptyEl.style.display='none';let displayData=[...bondsData].sort((a,b)=>b.current_value-a.current_value);if(!allocationChartExpanded && displayData.length>10){const top10=displayData.slice(0,10);const others=displayData.slice(10);const otherValue=others.reduce((sum,b)=>sum+b.current_value,0);displayData=[...top10,{name:'Другое',current_value:otherValue,isOther:true}];}const labels=displayData.map(b=>b.name);const values=displayData.map(b=>b.current_value);const colors=displayData.map((_,i)=>{if(displayData[i].isOther)return '#94a3b8';return `hsl(${Math.round((i * 137.5)% 360)},60%,55%)`;});if(allocationChartInstance)allocationChartInstance.destroy();allocationChartInstance=new Chart(canvas.getContext('2d'),{type:'doughnut',data:{labels,datasets:[{data:values,backgroundColor:colors,borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,onClick:(e,elements)=>{if(!elements.length)return;const idx=elements[0].index;if(!allocationChartExpanded && displayData[idx].isOther){allocationChartExpanded=true;renderAllocationChart();}},plugins:{legend:{position:'right',labels:{font:{size:10},boxWidth:12}},tooltip:{callbacks:{label:ctx=>{const total=ctx.dataset.data.reduce((s,v)=>s+v,0);const pct=total ?((ctx.parsed / total)* 100).toFixed(1):0;return ` ${ctx.parsed.toLocaleString('ru-RU',{maximumFractionDigits:0})}₽(${pct}%)`;}}}}}});}async function fetchChartAnalytics(){const response=await fetch('/api/portfolio_stats');if(!response.ok)return;const chartData=await response.json();const ctx=document.getElementById('profitChart');if(!ctx)return;if(myChartInstance)myChartInstance.destroy();myChartInstance=new Chart(ctx.getContext('2d'),{type:'bar',data:chartData,options:{responsive:true,maintainAspectRatio:false}});}async function fetchSharpeRatio(){try{const r=await fetch('/api/portfolio/sharpe');if(!r.ok)return;const data=await r.json();const el=document.getElementById('sharpeValue');const sub=document.getElementById('sharpeSub');const sampleEl=document.getElementById('sharpeSampleSize');if(!el)return;if(data.sharpe==null){el.textContent='—';if(sub)sub.textContent=data.reason || '';return;}const sharpe=parseFloat(data.sharpe);el.textContent=sharpe.toFixed(2);el.style.color=sharpe>=1 ? 'var(--emerald-500)':sharpe>=0 ? 'var(--text-info)':'#ef4444';if(sub)sub.textContent=`Доход:${data.mean_return_pct}% · Волат.:${data.volatility_pct}%`;if(sampleEl)sampleEl.textContent=` · ${data.sample_size}сделок`;}catch(_){}}function loadTaxIfNeeded(){if(!taxLoaded)loadTax();}async function loadTax(){const yearSelect=document.getElementById('taxYearSelect');const year=yearSelect ? yearSelect.value:new Date().getFullYear();const loadEl=document.getElementById('tax-loading');const summaryEl=document.getElementById('taxSummary');const tableWrap=document.getElementById('taxTableWrap');const emptyEl=document.getElementById('taxEmpty');if(loadEl)loadEl.style.display='block';if(summaryEl)summaryEl.style.display='none';if(tableWrap)tableWrap.style.display='none';if(emptyEl)emptyEl.style.display='none';try{const r=await fetch(`/api/portfolio/tax?year=${year}`);if(!r.ok)return;const data=await r.json();if(loadEl)loadEl.style.display='none';const trades=data.trades ||[];if(!trades.length){if(emptyEl)emptyEl.style.display='block';return;}const _fmt=v=>v !=null ? v.toLocaleString('ru-RU',{minimumFractionDigits:2,maximumFractionDigits:2})+' ₽':'—';const el=id=>document.getElementById(id);if(el('taxGrossProfit'))el('taxGrossProfit').textContent=_fmt(data.gross_profit);if(el('taxTotalComm'))el('taxTotalComm').textContent=_fmt(data.total_commission);if(el('taxBase'))el('taxBase').textContent=_fmt(data.taxable_base);if(el('taxAmount'))el('taxAmount').textContent=_fmt(data.tax_amount);if(summaryEl)summaryEl.style.display='grid';const tbody=document.getElementById('tax-table-body');if(tbody){const esc=window.Common.escapeHtml;tbody.innerHTML=trades.map(t=>{const pnlCls=t.pnl>=0 ? 'text-success':'text-danger';let rowHtml=`<tr><td data-label="Название">${esc(t.name)}</td><td data-label="ISIN"><code style="font-size:.78rem">${esc(t.isin)}</code></td><td data-label="Кол-во">${t.amount}</td><td data-label="Цена покупки">${(t.buy_price || 0).toFixed(2)}</td><td data-label="Цена продажи">${t.sell_price !=null ? t.sell_price.toFixed(2):'—'}</td><td data-label="Комиссия">${(t.commission || 0).toFixed(2)}</td><td data-label="Купоны">${(t.coupons || 0).toFixed(2)}</td><td data-label="P&L ₽" class="${pnlCls}">${t.pnl>=0 ? '+':''}${(t.pnl || 0).toFixed(2)}</td><td data-label="Дата продажи">${esc(t.sell_date || '—')}${t.sub_trades ? `<button class="btn btn-sm btn-link p-0 ms-1" onclick="toggleSubTrades('sub-${t.id}')">▾</button>`:''}</td></tr>`;if(t.sub_trades){const subRows=t.sub_trades.map(st=>{const subPnlCls=st.pnl>=0 ? 'text-success':'text-danger';return `<tr><td colspan="2"></td><td class="text-muted small">${st.amount}шт.</td><td colspan="2"></td><td class="text-muted small">${(st.commission || 0).toFixed(2)}₽</td><td></td><td class="${subPnlCls}small">${st.pnl>=0 ? '+':''}${(st.pnl || 0).toFixed(2)}₽</td><td class="text-muted small">${esc(st.time || '')}</td></tr>`;}).join('');rowHtml+=`<tr id="sub-${t.id}" style="display:none;background:var(--surface-0)"><td colspan="9" style="padding:0"><table class="table table-sm table-borderless mb-0" style="font-size:0.85rem"><tbody>${subRows}</tbody></table></td></tr>`;}return rowHtml;}).join('');}if(tableWrap)tableWrap.style.display='block';taxLoaded=true;}catch(_){if(loadEl)loadEl.style.display='none';if(emptyEl)emptyEl.style.display='block';}}function toggleSubTrades(id){const el=document.getElementById(id);if(el)el.style.display=el.style.display==='none' ? 'table-row':'none';}async function runCompare(){const isin1=(document.getElementById('compareIsin1')?.value || '').trim().toUpperCase();const isin2=(document.getElementById('compareIsin2')?.value || '').trim().toUpperCase();const range=document.getElementById('compareRange')?.value || 'month';if(!isin1 || !isin2){window.Common.showToast('Введите оба ISIN',true);return;}if(isin1===isin2){window.Common.showToast('ISIN должны быть разными',true);return;}const loadEl=document.getElementById('compare-loading');const emptyEl=document.getElementById('compareEmpty');const legendEl=document.getElementById('compareLegend');if(loadEl)loadEl.style.display='block';if(emptyEl)emptyEl.style.display='none';if(legendEl)legendEl.style.display='none';try{const r=await fetch(`/api/portfolio/compare?isin1=${isin1}&isin2=${isin2}&range=${range}`);const data=await r.json();if(loadEl)loadEl.style.display='none';if(!data.status || data.status !=='success'){window.Common.showToast(data.message || 'Ошибка загрузки',true);if(emptyEl)emptyEl.style.display='block';return;}const labels=data.labels ||[];const d1=data.bond1?.data ||[];const d2=data.bond2?.data ||[];if(!labels.length){if(emptyEl)emptyEl.style.display='block';return;}const n1El=document.getElementById('compareName1');const n2El=document.getElementById('compareName2');if(n1El)n1El.textContent=data.bond1?.name || isin1;if(n2El)n2El.textContent=data.bond2?.name || isin2;if(legendEl)legendEl.style.display='flex';onChartJsReady(()=>{const ctx=document.getElementById('compareChart');if(!ctx)return;if(compareChartInstance)compareChartInstance.destroy();compareChartInstance=new Chart(ctx.getContext('2d'),{type:'line',data:{labels,datasets:[{label:data.bond1?.name || isin1,data:d1,borderColor:'#3b82f6',backgroundColor:'rgba(59,130,246,.08)',borderWidth:2,fill:false,tension:0.25,pointRadius:0,pointHoverRadius:4,},{label:data.bond2?.name || isin2,data:d2,borderColor:'#f59e0b',backgroundColor:'rgba(245,158,11,.06)',borderWidth:2,fill:false,tension:0.25,pointRadius:0,pointHoverRadius:4,},],},options:{responsive:true,maintainAspectRatio:false,interaction:{mode:'index',intersect:false},plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>` ${ctx.dataset.label}:${ctx.parsed.y.toFixed(2)}`,},},},scales:{x:{ticks:{maxTicksLimit:8,font:{size:11},color:'var(--text-tertiary)'},grid:{display:false},},y:{ticks:{font:{size:11},color:'var(--text-tertiary)',callback:v=>v.toFixed(1)},grid:{color:'rgba(var(--accent-rgb),.06)'},},},},});});}catch(_){if(loadEl)loadEl.style.display='none';if(emptyEl)emptyEl.style.display='block';window.Common.showToast('Ошибка загрузки данных MOEX',true);}}function clearCompare(){['compareIsin1','compareIsin2'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});if(compareChartInstance){compareChartInstance.destroy();compareChartInstance=null;}const emptyEl=document.getElementById('compareEmpty');if(emptyEl)emptyEl.style.display='block';const legendEl=document.getElementById('compareLegend');if(legendEl)legendEl.style.display='none';}function loadBenchmarkIfNeeded(){if(!benchmarkLoaded)loadBenchmark(benchmarkRange);}function setBenchmarkRange(range,btn){benchmarkRange=range;document.querySelectorAll('#benchmarkRangeBtns button').forEach(b=>b.classList.remove('active'));if(btn)btn.classList.add('active');benchmarkLoaded=false;loadBenchmark(range);}async function loadBenchmark(range){const loadEl=document.getElementById('benchmark-loading');const emptyEl=document.getElementById('benchmarkEmpty');const statsEl=document.getElementById('benchmarkStats');if(loadEl)loadEl.style.display='block';if(emptyEl)emptyEl.style.display='none';if(statsEl)statsEl.style.display='none';try{const r=await fetch(`/api/portfolio/benchmark?range=${range}`);const data=await r.json();if(loadEl)loadEl.style.display='none';let labels=[],values=[];if(data.rgbi && Array.isArray(data.rgbi.labels)&& Array.isArray(data.rgbi.data)){labels=data.rgbi.labels;values=data.rgbi.data.map(v=>parseFloat(v));}else if(Array.isArray(data.rgbi)){const rows=data.rgbi.filter(d=>d.close || d.value);labels=rows.map(d=>d.date || d.tradedate || '');values=rows.map(d=>parseFloat(d.close || d.value || 0));}if(!labels.length){if(emptyEl)emptyEl.style.display='block';return;}const first=values[0],last=values[values.length-1];const chg=last-first;const chgPct=first ?(chg / first * 100):0;if(document.getElementById('benchmarkFirst'))document.getElementById('benchmarkFirst').textContent=first.toFixed(2);if(document.getElementById('benchmarkLast'))document.getElementById('benchmarkLast').textContent=last.toFixed(2);const chgEl=document.getElementById('benchmarkChange');if(chgEl){const sign=chg>=0 ? '+':'';chgEl.textContent=`${sign}${chg.toFixed(2)}(${sign}${chgPct.toFixed(2)}%)`;chgEl.style.color=chg>=0 ? 'var(--emerald-500)':'#ef4444';}if(statsEl)statsEl.style.display='flex';onChartJsReady(()=>{const ctx=document.getElementById('benchmarkChart');if(!ctx)return;if(benchmarkChartInstance)benchmarkChartInstance.destroy();const color=chg>=0 ? '#10b981':'#ef4444';benchmarkChartInstance=new Chart(ctx.getContext('2d'),{type:'line',data:{labels,datasets:[{label:'RGBI',data:values,borderColor:color,backgroundColor:color+'18',borderWidth:2,fill:true,tension:0.3,pointRadius:0,pointHoverRadius:4,}],},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>` ${ctx.parsed.y.toFixed(2)}`}},},scales:{x:{ticks:{maxTicksLimit:8,font:{size:11},color:'var(--text-tertiary)'},grid:{display:false},},y:{ticks:{font:{size:11},color:'var(--text-tertiary)'},grid:{color:'rgba(var(--accent-rgb),.06)'},},},},});benchmarkLoaded=true;});}catch(_){if(loadEl)loadEl.style.display='none';if(emptyEl)emptyEl.style.display='block';}}let _couponsAllCache=null;async function _loadCouponsAll(){if(_couponsAllCache)return _couponsAllCache;try{const r=await fetch('/api/portfolio/calendar?limit=1000');_couponsAllCache=r.ok ? await r.json():[];}catch(_){_couponsAllCache=[];}return _couponsAllCache;}async function renderCouponsMini(){const list=document.getElementById('coupon-calendar-list-mini');if(!list)return;const events=await _loadCouponsAll();if(!events || !events.length){list.innerHTML='<li class="list-group-item text-center py-2" style="font-size:.82rem;color:var(--text-tertiary)">Нет предстоящих купонов.</li>';return;}const esc=window.Common.escapeHtml;list.innerHTML=events.slice(0,5).map(e=>`<li class="list-group-item d-flex justify-content-between align-items-center" style="padding:.45rem .75rem"><div style="min-width:0;flex:1"><div class="fw-semibold text-truncate" style="font-size:.78rem">${esc(e.name)}</div><div class="text-muted" style="font-size:.7rem">${esc(e.date)}</div></div><span class="badge bg-success font-monospace ms-2" style="font-size:.7rem">+${parseFloat(e.total_payout).toFixed(2)}₽</span></li>`).join('');}let _couponsModalDays=90;async function renderCouponsModal(){const loadEl=document.getElementById('couponsModalLoading');const emptyEl=document.getElementById('couponsModalEmpty');const listEl=document.getElementById('couponsModalList');const sumEl=document.getElementById('couponsModalSummary');if(!listEl)return;if(loadEl)loadEl.style.display='block';if(emptyEl)emptyEl.style.display='none';listEl.style.display='none';listEl.innerHTML='';const all=await _loadCouponsAll();if(loadEl)loadEl.style.display='none';const today=new Date();today.setHours(0,0,0,0);let events=all ||[];if(_couponsModalDays>0){const horizon=new Date(today.getTime()+_couponsModalDays * 86400000);events=events.filter(e=>{const d=new Date(e.date);return d>=today && d<=horizon;});}if(!events.length){if(emptyEl)emptyEl.style.display='block';if(sumEl)sumEl.textContent='';return;}const esc=window.Common.escapeHtml;const total=events.reduce((s,e)=>s+(parseFloat(e.total_payout)|| 0),0);const fmtRub=v=>v.toLocaleString('ru-RU',{minimumFractionDigits:2,maximumFractionDigits:2});listEl.innerHTML=events.map(e=>`<li class="list-group-item d-flex justify-content-between align-items-center" style="padding:.7rem 1rem"><div style="min-width:0;flex:1"><div class="fw-semibold" style="font-size:.88rem">${esc(e.name)}</div><div class="text-muted small">${esc(e.isin || '')}· ${esc(e.date)}</div></div><span class="badge bg-success font-monospace ms-2" style="font-size:.85rem;padding:.4rem .6rem">+${fmtRub(parseFloat(e.total_payout))}₽</span></li>`).join('');listEl.style.display='block';if(sumEl)sumEl.textContent=`Всего ${events.length}выплат · итого+${fmtRub(total)}₽`;}let _yieldPeriod='1m';let _yieldMode='all';const _fmtRub=v=>v.toLocaleString('ru-RU',{minimumFractionDigits:2,maximumFractionDigits:2});async function loadYield(){const valEl=document.getElementById('yieldValue');const cEl=document.getElementById('yieldCoupons');const rEl=document.getElementById('yieldRealized');const uEl=document.getElementById('yieldUnrealized');if(!valEl)return;valEl.textContent='…';try{const r=await fetch(`/api/portfolio/yield?period=${_yieldPeriod}&mode=${_yieldMode}`);if(!r.ok){valEl.textContent='—';return;}const d=await r.json();const t=parseFloat(d.total)|| 0;const sign=t>=0 ? '+':'−';valEl.textContent=`${sign}${_fmtRub(Math.abs(t))}₽`;valEl.style.color=t>=0 ? 'var(--emerald-500,#10b981)':'#ef4444';if(cEl)cEl.textContent=`+${_fmtRub(parseFloat(d.coupons)|| 0)}₽`;if(rEl){const v=parseFloat(d.realized_pnl)|| 0;rEl.textContent=`${v>=0 ? '+':'−'}${_fmtRub(Math.abs(v))}₽`;rEl.style.color=v>=0 ? 'var(--emerald-500,#10b981)':'#ef4444';}if(uEl){const v=parseFloat(d.unrealized_pnl)|| 0;uEl.textContent=`${v>=0 ? '+':'−'}${_fmtRub(Math.abs(v))}₽`;uEl.style.color=v>=0 ? 'var(--emerald-500,#10b981)':'#ef4444';}const bd=document.getElementById('yieldBreakdown');if(bd){const showAll=_yieldMode==='all';bd.querySelectorAll('span').forEach((s,idx)=>{if(idx===0)return;s.style.display=showAll ? '':'none';});}}catch(_){valEl.textContent='—';}}async function loadCouponsReceived(){const el=document.getElementById('couponsReceivedValue');if(!el)return;try{const r=await fetch('/api/portfolio/coupons_received?period=all');if(!r.ok){el.textContent='—';return;}const d=await r.json();const v=parseFloat(d.total)|| 0;el.textContent=`+${_fmtRub(v)}₽`;el.style.color='var(--emerald-500,#10b981)';}catch(_){el.textContent='—';}}document.addEventListener('DOMContentLoaded',()=>{fetchActivePortfolio();fetchChartAnalytics();fetchSharpeRatio();loadTax();renderCouponsMini();loadYield();loadCouponsReceived();document.querySelectorAll('#yieldPeriodBtns button').forEach(btn=>{btn.addEventListener('click',()=>{document.querySelectorAll('#yieldPeriodBtns button').forEach(b=>b.classList.remove('active'));btn.classList.add('active');_yieldPeriod=btn.dataset.period;loadYield();});});document.querySelectorAll('#yieldModeBtns button').forEach(btn=>{btn.addEventListener('click',()=>{document.querySelectorAll('#yieldModeBtns button').forEach(b=>b.classList.remove('active'));btn.classList.add('active');_yieldMode=btn.dataset.mode;loadYield();});});const modalEl=document.getElementById('couponsModal');if(modalEl)modalEl.addEventListener('show.bs.modal',renderCouponsModal);document.querySelectorAll('#couponsPeriodBtns button').forEach(btn=>{btn.addEventListener('click',()=>{document.querySelectorAll('#couponsPeriodBtns button').forEach(b=>b.classList.remove('active'));btn.classList.add('active');_couponsModalDays=parseInt(btn.dataset.days,10)|| 0;renderCouponsModal();});});document.getElementById('taxYearSelect')?.addEventListener('change',()=>{taxLoaded=false;loadTax();});document.getElementById('compareRunBtn')?.addEventListener('click',runCompare);document.getElementById('compareClearBtn')?.addEventListener('click',clearCompare);document.querySelectorAll('#benchmarkRangeBtns button').forEach(btn=>{btn.addEventListener('click',(e)=>{const range=e.target.dataset.range || 'month';setBenchmarkRange(range,e.target);});});document.getElementById('tax-tab')?.addEventListener('click',loadTaxIfNeeded);document.getElementById('benchmark-tab')?.addEventListener('click',loadBenchmarkIfNeeded);});